import{_ as t,o as d,c as n,a2 as a}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Pagina-instellingen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Page/page-settings.md","filePath":"nl-NL/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"nl-NL/Page/page-settings.md"};function o(i,e,l,g,s,h){return d(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="pagina-instellingen" tabindex="-1">Pagina-instellingen <a class="header-anchor" href="#pagina-instellingen" aria-label="Permalink to &quot;Pagina-instellingen&quot;">​</a></h1><p>Pagina-instellingen regelen de weergave van de site, standaardwaarden van de uploadpagina, achtergrondafbeeldingen en het uiterlijk van het beheerpaneel.</p><h2 id="algemene-instellingen" tabindex="-1">Algemene instellingen <a class="header-anchor" href="#algemene-instellingen" aria-label="Permalink to &quot;Algemene instellingen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Doel</th></tr></thead><tbody><tr><td>Sitetitel</td><td>Titel die in het browsertabblad wordt getoond.</td></tr><tr><td>Site-icoon</td><td>Klein icoon in het browsertabblad.</td></tr><tr><td>ImgBed-naam</td><td>Naam die op de frontendpagina&#39;s wordt getoond.</td></tr><tr><td>ImgBed-logo</td><td>Logo-afbeelding op de frontendpagina&#39;s.</td></tr><tr><td>Logolink</td><td>URL die opent wanneer je op logo of avatar klikt.</td></tr><tr><td>Wisselinterval achtergrond</td><td>Rotatie-interval voor meerdere achtergronden, in milliseconden. <code>60000</code> betekent 60 seconden.</td></tr><tr><td>Achtergronddekking</td><td>Dekking van de achtergrondafbeelding van <code>0</code> tot <code>1</code>. Lagere waarden zijn lichter.</td></tr><tr><td>Standaard URL-prefix</td><td>Prefix voor gegenereerde afbeeldingslinks. Leeg betekent dat het huidige sitedomein wordt gebruikt.</td></tr></tbody></table><h2 id="clientinstellingen" tabindex="-1">Clientinstellingen <a class="header-anchor" href="#clientinstellingen" aria-label="Permalink to &quot;Clientinstellingen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Doel</th></tr></thead><tbody><tr><td>Aankondiging</td><td>Bericht bovenaan de uploadpagina. HTML wordt ondersteund.</td></tr><tr><td>Standaard uploadkanaal</td><td>Kanaal dat standaard op de uploadpagina is geselecteerd. Je kunt ook Smart Dispatch kiezen.</td></tr><tr><td>Standaard uploadmap</td><td>Standaard uploadmap, bijvoorbeeld <code>/user/</code>. Leeg of <code>/</code> betekent root.</td></tr><tr><td>Standaard naamgevingsmethode</td><td>Strategie voor het genereren van bestandsnamen na upload. Zie hieronder.</td></tr><tr><td>Standaard naar WebP converteren</td><td>Zet afbeeldingen vóór upload om naar WebP.</td></tr><tr><td>Standaard compressie inschakelen</td><td>Comprimeert afbeeldingen lokaal in de browser vóór upload.</td></tr><tr><td>Standaard compressiedrempel</td><td>Comprimeert automatisch wanneer een afbeelding groter is dan deze waarde, in MB.</td></tr><tr><td>Standaard doelgrootte</td><td>Gewenste bestandsgrootte na compressie, in MB.</td></tr><tr><td>Achtergrond loginpagina</td><td>Achtergrondafbeelding voor de gebruikersloginpagina.</td></tr><tr><td>Achtergrond uploadpagina</td><td>Achtergrondafbeelding voor de uploadpagina.</td></tr><tr><td>Footer-portaallink</td><td>URL die opent via de portaalknop in de footer.</td></tr><tr><td>Footer verbergen</td><td>Verbergt de frontendfooter wanneer ingeschakeld.</td></tr></tbody></table><h2 id="beheerinstellingen" tabindex="-1">Beheerinstellingen <a class="header-anchor" href="#beheerinstellingen" aria-label="Permalink to &quot;Beheerinstellingen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Doel</th></tr></thead><tbody><tr><td>Achtergrond admin-login</td><td>Achtergrondafbeelding voor de admin-loginpagina.</td></tr><tr><td>Admin-achtergrond</td><td>Achtergrondafbeelding voor beheerpagina&#39;s. Gebruik één afbeeldings-URL of meerdere URL&#39;s.</td></tr><tr><td>Afbeeldingslaadmodus</td><td>Previewmodus voor de bestandslijst in beheer. Original laadt originele afbeeldingen. Smart loading gebruikt thumbnails voor openbare afbeeldingen en originelen voor beperkte afbeeldingen.</td></tr><tr><td>Thumbnailbron</td><td>Dienst voor thumbnails: wsrv.nl, Cloudflare Image Resizing of WordPress Photon. Cloudflare Image Resizing moet in Cloudflare zijn ingeschakeld voordat je dit kiest.</td></tr><tr><td>Live2D-widget</td><td>Toont een Live2D-personage in het beheerpaneel.</td></tr><tr><td>Vuurwerk bij klikken</td><td>Toont een vuurwerkeffect wanneer je op de pagina klikt.</td></tr><tr><td>Sterrenspoor cursor</td><td>Toont een sterrenspoor wanneer je de muis beweegt.</td></tr></tbody></table><h2 id="formaten-voor-achtergrondafbeeldingen" tabindex="-1">Formaten voor achtergrondafbeeldingen <a class="header-anchor" href="#formaten-voor-achtergrondafbeeldingen" aria-label="Permalink to &quot;Formaten voor achtergrondafbeeldingen&quot;">​</a></h2><p>Achtergrond van loginpagina, uploadpagina en admin-login ondersteunen deze waarden:</p><table tabindex="0"><thead><tr><th>Waarde</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Gebruikt de Bing-achtergrondrotatie.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Roteert meerdere afbeeldingen.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Gebruikt één achtergrondafbeelding.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Gebruikt een Random Image API-link. Je kunt je eigen Random Image API instellen onder Andere instellingen en de gegenereerde link hier als enkele achtergrond gebruiken.</td></tr></tbody></table><p>De admin-achtergrond ondersteunt afbeeldings-URL&#39;s. Meerdere URL&#39;s kunnen met Engelse komma&#39;s worden gescheiden, zoals op de pagina wordt aangegeven. Leeg betekent dat de standaardachtergrond wordt gebruikt.</p><h2 id="standaard-naamgevingsmethode" tabindex="-1">Standaard naamgevingsmethode <a class="header-anchor" href="#standaard-naamgevingsmethode" aria-label="Permalink to &quot;Standaard naamgevingsmethode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Methode</th><th>Resultaat</th></tr></thead><tbody><tr><td>Default</td><td>Tijd-willekeurig prefix + oorspronkelijke bestandsnaam, bijvoorbeeld <code>1760000000000_cat.png</code>.</td></tr><tr><td>Alleen prefix</td><td>Tijd-willekeurig prefix en extensie, bijvoorbeeld <code>1760000000000.png</code>.</td></tr><tr><td>Alleen oorspronkelijke naam</td><td>Houdt de oorspronkelijke bestandsnaam, bijvoorbeeld <code>cat.png</code>. Bij duplicaten voegt ImgBed <code>(1)</code>, <code>(2)</code> enzovoort toe.</td></tr><tr><td>Korte link</td><td>Gebruikt een korte ID van 8 tekens en extensie, bijvoorbeeld <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const p=t(r,[["render",o]]);export{c as __pageData,p as default};
